/**
 * GHL API Client
 * 
 * Wrapper for GoHighLevel REST API calls with automatic token refresh
 */

import { TokenService } from '../services/token.service';

export interface GHLApiConfig {
  locationId: string;
  maxRetries?: number;
}

interface WebhookResponse {
  webhooks?: Array<{
    id: string;
    url: string;
    events: string[];
    [key: string]: any;
  }>;
}

export class GHLApiClient {
  private locationId: string;
  private maxRetries: number;
  private tokenService = new TokenService();
  
  constructor(config: GHLApiConfig) {
    this.locationId = config.locationId;
    this.maxRetries = config.maxRetries || 3;
  }
  
  /**
   * Make authenticated request to GHL API with automatic token refresh
   */
  async request<T = any>(
    endpoint: string,
    options: RequestInit = {}
  ): Promise<T> {
    let lastError: Error | null = null;
    
    for (let attempt = 0; attempt < this.maxRetries; attempt++) {
      try {
        // Get valid access token (auto-refreshes if needed)
        const accessToken = await this.tokenService.getValidAccessToken(this.locationId);
        
        const response = await fetch(`https://services.leadconnectorhq.com${endpoint}`, {
          ...options,
          headers: {
            'Authorization': `Bearer ${accessToken}`,
            'Content-Type': 'application/json',
            'Version': '2021-07-28',
            ...options.headers,
          },
        });
        
        if (response.status === 401) {
          // Token might be invalid, force refresh and retry
          await this.tokenService.refreshToken(this.locationId);
          continue;
        }
        
        if (response.status === 429) {
          // Rate limited, wait and retry
          const retryAfter = parseInt(response.headers.get('Retry-After') || '5');
          await new Promise(resolve => setTimeout(resolve, retryAfter * 1000));
          continue;
        }
        
        if (!response.ok) {
          throw new Error(`GHL API error: ${response.status} ${response.statusText}`);
        }
        
        return await response.json();
      } catch (error) {
        lastError = error instanceof Error ? error : new Error('Unknown error');
        
        if (attempt < this.maxRetries - 1) {
          // Exponential backoff
          const delay = Math.pow(2, attempt) * 1000;
          await new Promise(resolve => setTimeout(resolve, delay));
        }
      }
    }
    
    throw lastError || new Error('Request failed after retries');
  }
  
  /**
   * Get location details
   */
  async getLocation(): Promise<any> {
    return this.request(`/locations/${this.locationId}`);
  }
  
  /**
   * List contacts
   */
  async listContacts(params?: {
    limit?: number;
    skip?: number;
  }): Promise<any> {
    const queryParams = new URLSearchParams();
    if (params?.limit) queryParams.set('limit', params.limit.toString());
    if (params?.skip) queryParams.set('skip', params.skip.toString());
    
    return this.request(`/contacts/?locationId=${this.locationId}&${queryParams.toString()}`);
  }
  
  /**
   * Get contact by ID
   */
  async getContact(contactId: string): Promise<any> {
    return this.request(`/contacts/${contactId}`);
  }
  
  /**
   * Update contact
   */
  async updateContact(contactId: string, data: any): Promise<any> {
    return this.request(`/contacts/${contactId}`, {
      method: 'PUT',
      body: JSON.stringify(data),
    });
  }
  
  /**
   * List webhooks
   */
  async listWebhooks(): Promise<WebhookResponse> {
    return this.request<WebhookResponse>(`/webhooks/?locationId=${this.locationId}`);
  }
  
  /**
   * Create webhook
   */
  async createWebhook(data: {
    url: string;
    events: string[];
    locationId: string;
  }): Promise<any> {
    return this.request(`/webhooks/`, {
      method: 'POST',
      body: JSON.stringify(data),
    });
  }
  
  /**
   * Delete webhook
   */
  async deleteWebhook(webhookId: string): Promise<void> {
    await this.request(`/webhooks/${webhookId}`, {
      method: 'DELETE',
    });
  }
}